#ifndef SERVO_MOTOR_H
#define SERVO_MOTOR_H

#include <Servo.h>

class ServoMotor {
public:
    void setup(int pin, int min_pulse, int max_pulse);
    void loop(float angle);
    float getCurrentAngle() const;

private:
    Servo servo;
    int current_angle = 0;
};

#endif // SERVO_MOTOR_H

firmware_template.source:
#include "servo_motor.h"

void ServoMotor::setup(int pin, int min_pulse, int max_pulse) {
    servo.attach(pin, min_pulse, max_pulse);
    if (!servo.attached()) {
        Serial.println("[servo_motor] Failed to attach servo motor. Retrying...");
        delay(1000);
        setup(pin, min_pulse, max_pulse); // Retry
    }
}

void ServoMotor::loop(float angle) {
    if (angle < 0 || angle > 180) {
        Serial.println("[servo_motor] Invalid angle. Must be between 0 and 180 degrees.");
        return;
    }
    servo.write(angle);
    current_angle = angle;
}

float ServoMotor::getCurrentAngle() const {
    return current_angle;
}
